import React from 'react';
import { SvgXml } from 'react-native-svg';
import {
  View,
  TouchableOpacity,
  Alert,
  ActivityIndicator,
  ScrollView,
  Platform,
  Animated,
} from 'react-native';
import { Text, CollectibleDrawer } from '@/components';
import { Image } from 'expo-image';
import * as Haptics from 'expo-haptics';
import { API_URL } from '@/lib/api';
import { useAuth } from '@/context/AuthContext';
import { useAccount } from '@/context/AccountContext';
import { useDogs } from '@/context/DogsContext';
import { useTrails } from '@/context/TrailsContext';

import { Mail, LogOut, Dog, MapPin, Star, BarChart3, Bookmark, LucideTableOfContents, ArrowRight } from 'lucide-react-native';
import theme from '@/constants/colors';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import styles from './profile.styles';
import { useRouter } from 'expo-router';
import { formatDistance } from '@/utils/distance';
import { LinearGradient } from 'expo-linear-gradient';
import TrailMapPreview from '@/components/TrailMapPreview';
// Use bundler require for local asset so Metro/Expo can resolve it reliably
const Icon = require('../../assets/images/icon.png');

type ProfileTab = 'created' | 'saved' | 'reviews';

export default function ProfileScreen() {
  const auth = useAuth();
  if (!auth) {
    return (
      <View style={styles.container}>
        <View style={styles.loadingContainer}>
          <ActivityIndicator size="large" color={theme.backgroundPrimary} />
        </View>
      </View>
    );
  }
  const { user, signOut, session } = auth;
  const { userProfile, isLoading: isAccountLoading } = useAccount();
  const { dogProfile, isDogProfileLoading } = useDogs();
  const { trails, savedTrails, isLoading: isTrailsLoading, saveTrailBookmark, removeTrailBookmark, isTrailSaved } = useTrails();
  const [isLoading, setIsLoading] = React.useState<boolean>(false);
  const [selectedTab, setSelectedTab] = React.useState<ProfileTab>('created');
  const [bookmarkAnimations, setBookmarkAnimations] = React.useState<Record<string, Animated.Value>>({});
  const insets = useSafeAreaInsets();
  const router = useRouter();


  const totalWalks = trails.length;
  const totalTime = trails.reduce((acc, trail) => acc + (trail.duration || 0), 0);
  const totalDistance = trails.reduce((acc, trail) => acc + trail.distance, 0);

  const getDayStreak = () => {
    try {
      const dayMs = 24 * 60 * 60 * 1000;
      const daysSet = new Set<number>();
      trails.forEach(t => {
        if (!t.date) return;
        const d = new Date(t.date);
        d.setHours(0, 0, 0, 0);
        daysSet.add(d.getTime());
      });

      let streak = 0;
      const today = new Date();
      today.setHours(0, 0, 0, 0);
      let cursor = today.getTime();

      while (daysSet.has(cursor)) {
        streak++;
        cursor -= dayMs;
      }

      return streak;
    } catch (e) {
      return 0;
    }
  };

  const dayStreak = getDayStreak();

  const [dogSvg, setDogSvg] = React.useState<string | null>(null);
  React.useEffect(() => {
    let mounted = true;
    (async () => {
      try {
        const resp = await fetch(`${API_URL}/uploads/proxy/stats/dog.svg`);
        if (!resp.ok) return;
        const txt = await resp.text();
        if (mounted) setDogSvg(txt);
      } catch (err) {
        // ignore
      }
    })();
    return () => { mounted = false; };
  }, []);

  // Collectibles
  const collectibleUrls = [
    `${API_URL}/uploads/proxy/collectibles/bone.svg`,
    `${API_URL}/uploads/proxy/collectibles/bowl.svg`,
    `${API_URL}/uploads/proxy/collectibles/sign.svg`,
  ];
  const [collectibleSvgs, setCollectibleSvgs] = React.useState<(string | null)[]>([null, null, null]);
  const [showCollectibleDrawer, setShowCollectibleDrawer] = React.useState(false);
  const [selectedCollectible, setSelectedCollectible] = React.useState<string | null>(null);

  React.useEffect(() => {
    let mounted = true;
    (async () => {
      const results: (string | null)[] = [null, null, null];
      await Promise.all(collectibleUrls.map(async (u, i) => {
        try {
          const r = await fetch(u);
          if (!r.ok) return;
          const t = await r.text();
          results[i] = t;
        } catch (err) {
          // ignore
        }
      }));
      if (mounted) setCollectibleSvgs(results);
    })();
    return () => { mounted = false; };
  }, []);

  const formatTime = (seconds: number): string => {
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    if (hours > 0) {
      return `${hours}.${Math.floor(minutes / 6)}h`;
    }
    return `${minutes}m`;
  };

  const handleTabPress = (tab: ProfileTab) => {
    if (true) {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    }
    setSelectedTab(tab);
  };

  const handleNavigateToTrail = (trailId: string) => {
    if (true) {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    }
    router.push(`/trail/${trailId}`);
  };

  const getBookmarkAnimation = (trailId: string) => {
    if (!bookmarkAnimations[trailId]) {
      const newAnim = new Animated.Value(1);
      setBookmarkAnimations(prev => ({ ...prev, [trailId]: newAnim }));
      return newAnim;
    }
    return bookmarkAnimations[trailId];
  };

  const handleBookmarkPress = async (trailId: string) => {
    if (true) {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    }

    const anim = getBookmarkAnimation(trailId);
    const isSaved = isTrailSaved(trailId);

    Animated.sequence([
      Animated.timing(anim, {
        toValue: 0.6,
        duration: 100,
        useNativeDriver: true,
      }),
      Animated.spring(anim, {
        toValue: 1,
        friction: 3,
        tension: 100,
        useNativeDriver: true,
      }),
    ]).start();

    try {
      if (isSaved) {
        await removeTrailBookmark(trailId);
      } else {
        await saveTrailBookmark(trailId);
        if (true) {
          Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
        }
      }
    } catch (error) {
      console.error('Failed to toggle bookmark:', error);
    }
  };

  const handleSignOut = async () => {
    if (true) {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    }
    Alert.alert(
      'Sign Out',
      'Are you sure you want to sign out?',
      [
        { text: 'Cancel', style: 'cancel' },
        {
          text: 'Sign Out',
          style: 'destructive',
          onPress: async () => {
            if (true) {
              Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
            }
            setIsLoading(true);
            try {
              await signOut();
            } catch (error: any) {
              if (true) {
                Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error);
              }
              Alert.alert('Error', error.message || 'Failed to sign out');
            } finally {
              setIsLoading(false);
            }
          },
        },
      ]
    );
  };

  const handleEditDogProfile = () => {
    if (true) {
      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    }
    router.push('/onboarding/dog-profile');
  };

  const getDisplayedTrails = () => {
    if (selectedTab === 'created') return trails;
    if (selectedTab === 'saved') return savedTrails;
    return [];
  };

  const displayedTrails = getDisplayedTrails();

  return (
    <View style={styles.container}>
      <ScrollView style={styles.scrollContainer} contentContainerStyle={[styles.content, { paddingTop: insets.top + 16, paddingBottom: insets.bottom + 20 }]}>
        <View style={styles.userSection}>
          <View style={styles.userHeader}>
            <TouchableOpacity style={styles.userAvatar} onPress={() => router.push('/settings/account')}>
              {(userProfile?.image || Icon) ? (
                <Image
                  source={userProfile?.image || Icon}
                  style={styles.userAvatarImage}
                  contentFit="cover"
                  cachePolicy="memory-disk"
                />
              ) : (
                <View style={styles.initialAvatar}>
                  <Text style={styles.initialAvatarText}>{(userProfile?.name || user?.email || 'A').charAt(0).toUpperCase()}</Text>
                </View>
              )}
            </TouchableOpacity>
            <View style={styles.userInfo}>
              <Text style={styles.userName}>{userProfile?.name || user?.email?.split('@')[0] || 'Account Holder'}</Text>
              <View style={styles.userEmailRow}>
                <Mail size={14} color={theme.textSecondary} />
                <Text style={styles.userEmail}>{user?.email || 'Not available'}</Text>
              </View>
            </View>
            <TouchableOpacity
              style={styles.settingsButton}
              onPress={() => router.push('/settings')}
              accessibilityLabel="Open settings"
              accessibilityRole="button"
              hitSlop={{ top: 12, bottom: 12, left: 12, right: 12 }}
            >
              <LucideTableOfContents size={24} color={theme.textSecondary} />
            </TouchableOpacity>
          </View>
        </View>

        {isDogProfileLoading ? (
          <View style={styles.dogCardContainer}>
            <View style={styles.loadingDogCard}>
              <ActivityIndicator size="large" color={theme.accentPrimary} />
            </View>
          </View>
        ) : dogProfile ? (
          <View style={styles.dogCardContainer}>
            <TouchableOpacity style={styles.dogCard} onPress={handleEditDogProfile}>
              <View style={styles.dogPhotoContainer}>
                {dogProfile.image ? (
                  <Image
                    source={dogProfile.image}
                    style={styles.dogPhoto}
                    contentFit="cover"
                    cachePolicy="memory-disk"
                  />
                ) : (
                  <View style={[styles.dogPhoto, styles.dogPhotoPlaceholder]}>
                    <Dog size={40} color={theme.accentPrimary} />
                  </View>
                )}
              </View>

              <Text style={styles.dogName}>{dogProfile.name}</Text>
              {dogProfile.nickname && (
                <Text style={styles.dogNickname}>
                  {dogProfile.nickname}
                </Text>
              )}
              {!dogProfile.nickname && <View style={styles.nicknameSpacing} />}

              <View style={styles.statsRow}>
                <View style={styles.statItem}>
                  <Text style={styles.statValue}>{totalWalks}</Text>
                  <Text style={styles.statLabel}>Walks</Text>
                </View>
                <View style={styles.statItem}>
                  <Text style={styles.statValue}>{formatTime(totalTime)}</Text>
                  <Text style={styles.statLabel}>Total Time</Text>
                </View>
                <View style={styles.statItem}>
                  <Text style={styles.statValue}>{formatDistance(totalDistance)}</Text>
                  <Text style={styles.statLabel}>Total Dist.</Text>
                </View>
              </View>
            </TouchableOpacity>
          </View>
        ) : (
          <View style={styles.dogCardContainer}>
            <View style={styles.noDogCard}>
              <Dog size={48} color={theme.textMuted} />
              <Text style={styles.noDogText}>No dog profile yet</Text>
              <TouchableOpacity
                style={styles.addDogButton}
                onPress={handleEditDogProfile}
              >
                <Text style={styles.addDogButtonText}>Add Dog Profile</Text>
              </TouchableOpacity>
            </View>
          </View>
        )}

        <View style={styles.statsCardContainer}>
          <TouchableOpacity style={styles.statsCard} onPress={() => router.push('/stats')}>
            <View style={styles.statsCardHeader}>
              <Text style={styles.statsTitle}>Stats</Text>
              <ArrowRight size={18} color={theme.accentPrimary} />
            </View>

            <View style={styles.statsCardContent}>
              <View style={styles.statsSvgContainer}>
                <View style={styles.statsSvgRow}>
                  {[0,1,2,3].map((i) => (
                    <View key={i} style={styles.dogWrapper}>
                      {/** render fetched svg or placeholder box */}
                      {dogSvg ? (
                        <SvgXml xml={dogSvg} width={64} height={64} />
                      ) : (
                        <View style={styles.dogPlaceholder} />
                      )}
                    </View>
                  ))}
                </View>
                <View style={styles.dogCountBadge}>
                  <Text style={styles.dogCountText}>{totalWalks}</Text>
                </View>
              </View>
            </View>
          </TouchableOpacity>
        </View>

          {/* Collectibles (styled like Stats card) */}
          <View style={styles.statsCardContainer}>
            <TouchableOpacity style={styles.statsCard} onPress={() => router.push('/collectibles')}>
              <View style={styles.statsCardHeader}>
                <Text style={styles.statsTitle}>Collectibles</Text>
                <ArrowRight size={18} color={theme.accentPrimary} />
              </View>

              <View style={styles.statsCardContent}>
                <View style={styles.statsSvgContainer}>
                  <View style={styles.statsSvgRow}>
                    {collectibleSvgs.map((xml, i) => (
                      <TouchableOpacity
                        key={i}
                        style={styles.collectibleItem}
                        onPress={() => {
                          if (xml) setSelectedCollectible(xml);
                          setShowCollectibleDrawer(true);
                        }}
                        activeOpacity={0.8}
                      >
                        {xml ? (
                          <SvgXml xml={xml} width={64} height={64} />
                        ) : (
                          <View style={styles.collectiblePlaceholder} />
                        )}
                        <View style={[styles.collectibleOverlay, i === 0 ? { opacity: 0 } : { opacity: 0.55 }]} />
                      </TouchableOpacity>
                    ))}
                  </View>
                </View>
              </View>
            </TouchableOpacity>
          </View>

          {/* <CollectibleDrawer visible={showCollectibleDrawer} title="Collectible" onClose={() => { setShowCollectibleDrawer(false); setSelectedCollectible(null); }}>
            {selectedCollectible ? <SvgXml xml={selectedCollectible} width={180} height={180} /> : null}
          </CollectibleDrawer> */}

        <View style={styles.tabsContainer}>
          <TouchableOpacity
            style={[styles.tab, selectedTab === 'created' && styles.tabActive]}
            onPress={() => handleTabPress('created')}
          >
            <Text style={[styles.tabCount, selectedTab === 'created' && styles.tabCountActive]}>{trails.length}</Text>
            <Text style={[styles.tabText, selectedTab === 'created' && styles.tabTextActive]}>Created</Text>
          </TouchableOpacity>
          <TouchableOpacity
            style={[styles.tab, selectedTab === 'saved' && styles.tabActive]}
            onPress={() => handleTabPress('saved')}
          >
            <Text style={[styles.tabCount, selectedTab === 'saved' && styles.tabCountActive]}>{savedTrails.length}</Text>
            <Text style={[styles.tabText, selectedTab === 'saved' && styles.tabTextActive]}>Saved</Text>
          </TouchableOpacity>
          <TouchableOpacity
            style={[styles.tab, selectedTab === 'reviews' && styles.tabActive]}
            onPress={() => handleTabPress('reviews')}
          >
            <Text style={[styles.tabCount, selectedTab === 'reviews' && styles.tabCountActive]}>0</Text>
            <Text style={[styles.tabText, selectedTab === 'reviews' && styles.tabTextActive]}>Reviews</Text>
          </TouchableOpacity>
        </View>

        <View style={styles.trailsSection}>
          {isTrailsLoading ? (
            <View style={styles.loadingContainer}>
              <ActivityIndicator size="large" color={theme.backgroundPrimary} />
            </View>
          ) : displayedTrails.length > 0 ? (
            <View style={styles.verticalTrailsContainer}>
              {displayedTrails.map((trail) => {
                const anim = getBookmarkAnimation(trail.id);
                const isSaved = isTrailSaved(trail.id);
                return (
                  <TouchableOpacity
                    key={trail.id}
                    style={[styles.trailCard, styles.trailCardVertical]}
                    onPress={() => handleNavigateToTrail(trail.id)}
                  >
                    {trail.photo ? (
                      <Image source={{ uri: trail.photo }} style={styles.trailImage} />
                    ) : (
                      <TrailMapPreview
                        coordinates={trail.coordinates}
                        path={trail.path}
                        style={styles.trailImage}
                        startLatitude={trail.startLatitude}
                        startLongitude={trail.startLongitude}
                      />
                    )}

                    <TouchableOpacity
                      style={styles.bookmarkButton}
                      onPress={(e) => {
                        e.stopPropagation();
                        handleBookmarkPress(trail.id);
                      }}
                    >
                      <Animated.View style={{ transform: [{ scale: anim }] }}>
                        <Bookmark
                          size={20}
                          color={isSaved ? "#000" : theme.textMuted}
                          fill={isSaved ? "#000" : "none"}
                          strokeWidth={2}
                        />
                      </Animated.View>
                    </TouchableOpacity>

                    <View style={styles.trailContentBelow}>
                      <Text style={styles.trailName}>
                        {trail.name || `Trail ${new Date(trail.date).toLocaleDateString()}`}
                      </Text>
                      <Text style={styles.trailLocation}>
                        {trail.city ? `${trail.city}, ${trail.country || 'Unknown'}` : 'Location unknown'}
                      </Text>
                      <View style={styles.trailBadges}>
                        {trail.difficulty && (
                          <View style={styles.trailBadge}>
                            <BarChart3 size={14} color={theme.accentPrimary} strokeWidth={2.5} />
                            <Text style={styles.trailBadgeText}>{trail.difficulty}</Text>
                          </View>
                        )}
                        <View style={styles.trailBadge}>
                          <MapPin size={14} color={theme.accentPrimary} strokeWidth={2.5} />
                          <Text style={styles.trailBadgeText}>{formatDistance(trail.distance)}</Text>
                        </View>
                        {trail.rating && (
                          <View style={styles.trailBadge}>
                            <Star size={14} color={theme.accentPrimary} fill={theme.accentPrimary} strokeWidth={2} />
                            <Text style={styles.trailBadgeText}>{trail.rating.toFixed(1)}</Text>
                          </View>
                        )}
                      </View>
                    </View>
                  </TouchableOpacity>
                );
              })}
            </View>
          ) : (
            <View style={styles.emptyContainer}>
              <MapPin size={48} color={theme.textMuted} />
              <Text style={styles.emptyText}>
                {selectedTab === 'created'
                  ? 'No trails created yet'
                  : selectedTab === 'saved'
                    ? 'No trails saved yet'
                    : 'No reviews yet'}
              </Text>
            </View>
          )}
        </View>

      </ScrollView>
    </View>
  );
}
